INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027c77e3c98b0941765a5c', '此次广州之行第一站选择了花园酒店，非常满意。
房间设施、服务态度都是应有的水平，建筑本身也是风景。
最打动我的还是它独特的气质，而且很明显地感觉到，管理方有意营造这种热气腾腾、繁花似锦、芬芳馥郁的梦幻感。
当然也有一些问题，譬如面盆里有霉渍，深夜外面修路的声音还很嘈杂。但氛围感到位让人可以忽略。', '["https://dimg04.c-ctrip.com/images/0235312000d135y7u3442_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000d133fb69134_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000d13it9kA493_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000d13e41gF495_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-24', '红棉大床套房', '套房', '家庭亲子', 148, 0, 7, 8, '["整体满意度","房间设施","安静程度"]'::jsonb, '整体满意度', '房间设施', '安静程度'),
('68027c77e3c98b0941765a5d', '第二次入住了，价格有点贵但还是挺有当地特色的，服务不错。房间很大很舒服，虽然看得出已有一些些年代感了，但总体体验还是不错。每次checkin都会遇到阿联酋航空机组。唯一美中不足的是房间插座没有配备usb充电，最后问酒店借了一个充电器，也算是完美解决问题！', '["https://dimg04.c-ctrip.com/images/0230p12000d1sphzo93CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000d1spi017B34_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000d1spkr7D643_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000d1sq3020C05_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-26', '花园大床房', '大床房', '其他', 127, 0, 4, 8, '["房间设施","整体满意度","价格合理性"]'::jsonb, '房间设施', '整体满意度', '价格合理性'),
('68027c77e3c98b0941765a5e', '设施有复古风，只是空调设备噪音太大', '["https://dimg04.c-ctrip.com/images/0231i12000ex0t48o687B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000ex0tg85853C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000ex0trw0DD48_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-07-27', '花园双床房', '双床房', '商务出差', 17, 0, 87, 5, '["房间设施","安静程度"]'::jsonb, '房间设施', '安静程度', NULL),
('68027c77e3c98b0941765a5f', '亲子家庭出行，花园酒店的春节氛围浓郁，捏小泥人非常受孩子喜欢～
但是服务还是很受影响，没有欢迎水果，连住两晚，房间没有主动打扫。宝宝备品没有，床围没有，总之有点一言难尽', '["https://dimg04.c-ctrip.com/images/0231g12000d7qsqu72A0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000d7qvkdh7F63_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000d7qt41p91D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000d7qtol0E392_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-02-16', '花园大床房', '大床房', '家庭亲子', 84, 0, 17, 7, '["客房服务","整体满意度"]'::jsonb, '客房服务', '整体满意度', NULL),
('68027c77e3c98b0941765a60', '房间布局紧凑。进门在电梯后方，第一次遇到也是长见识了。
洗澡水压大，很舒服。早餐在30楼，鸡蛋和面食自主选择下单，第一天吃不懂，原来配菜很多量很大，第二天就知道少点了，节约粮食。
大厅果真气派，真不愧是白金五星级酒店，香氛味道很不错，4楼的博物馆和后花园瀑布一定要去参观。
以后有机会再来。', '["https://dimg04.c-ctrip.com/images/0235312000d2zovkr6AED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000d2zovkv75D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000d2zoxg46EE3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-30', '花园双床房', '双床房', '家庭亲子', 145, 0, 8, 8, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027c77e3c98b0941765a61', '阔别15年后再住花园酒店，没想到还这么棒。无论硬件设施还是服务质量绝对还是广州首选住宿酒店。酒店内后花园是国内众多高档酒店中难得一见的宝藏级花园。特别推荐三楼桃园馆的清蒸东星斑，非常好吃。', '["https://dimg04.c-ctrip.com/images/0231y12000d3a93yoDB2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000d3a9hwwD9EB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-31', '花园大床房', '大床房', '商务出差', 94, 0, 8, 8, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68027c82e3c98b0941765a62', '在结婚28周年纪念日选择了入住花园酒店，跟着礼宾小哥参观了酒店25个打卡点，在酒店博物馆听了广州酒店历史文化发展的专属介绍。特意选择了在荔湾庭晚餐，听着故仔和粤语旧歌，聊起在江边吃过的艇子粥，胜利宾馆的虾饺，老广州喝茶时拿着单子围着干蒸烧卖车边拿一盅两件边盖印章的趣事，耳边响起黄家驹的“喜欢你”不由唱起来，感觉太好了。前台小姐姐给我们升级了粤韵房，穿着汉服和旗袍拍了好多照片。最后，没有浪漫情怀，不善表达的老公说了一句“还是很高兴的哦”为这个特别的纪念日画上了美好的句号。', '["https://dimg04.c-ctrip.com/images/0235212000cmzglnuDB08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000cmzgvd4E73A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000cmzivuq1AE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000cmzk1zrC46B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000cmzhmgb106B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000cmzhre7AACC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000cmzlpbx9855_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000cmzhrqi433A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000cmzkfa3B4EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-26', '红棉大床套房', '套房', '情侣出游', 237, 0, 14, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027c82e3c98b0941765a63', '花园酒店不愧为老牌五星，卫生，服务都很不错，特别感谢前台niki服务意识和态度都很好还帮忙升级了房间，下次还会选择这里', '["https://dimg04.c-ctrip.com/images/0235912000eup7iah53E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000eupbppt3539_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000eupbaza8E73_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '花园大床房', '大床房', '商务出差', 59, 0, 8, 7, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027c82e3c98b0941765a64', '怎么说呢，依然金碧辉煌的大堂，照旧熙熙攘攘的人流，办入住的时候说我订的房型只有5层靠边的了，外面市政施工有噪音，给我们升级到套房，看了房间后发现原来是公寓楼不是客房，没有同意，出去吃饭回来后说安排好了还是原来的房型在20楼，能感觉到小伙子想尽力做到让客人满意，还好虽然晚上外面有施工但没影响休息。就是押金要第二天9点才能给退，感觉效率太低了，给人有点店大欺客的感觉。', '["https://dimg04.c-ctrip.com/images/0236f12000d2w2qpnB054_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000d2w2jvs183F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000d2w2p51E3C8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-30', '城央绿意双床房', '双床房', '家庭亲子', 183, 0, 7, 8, '["前台服务","退房/入住效率","安静程度"]'::jsonb, '前台服务', '退房/入住效率', '安静程度'),
('68027c82e3c98b0941765a65', '广州花园酒店的大招要从进入大门后开始——自接待厅起，一众充满岭南文化韵味的陈设与装饰，真的让人感觉走进了一座现代的艺术宫殿。接待厅的中央就陈列着当年那块“白金五星级酒店”的奖牌，它两侧的墙壁上分别挂着阳江手工漆画《百美图》与《百骏图》，静与动、柔与刚，相互呼应。进入大堂，最吸睛的莫过于前台背后的《红楼梦》大理石贴金壁画，它曾被国务院认证为全国最大的酒店大堂及镶金壁画。据说这副巨画由30多位工匠，花费7个多月才完工，用2公斤重的黄金做成20万片金箔，贴成了金陵十二钗的形象与故事...金庸先生2003年时也曾来此，并为这副画题字“花园酒店/如进荣国府/身在大观园”。与《红楼梦》壁画相对的墙上，是另一幅大理石壁画《广东水乡石刻壁画》，两幅壁画中间的空间，经常会更换放置一些限时的快闪展览装置，现在放置的是，主要面向孩子们的现场互动创作区，可以让他们在玻璃上随意进行色彩作画。', '["https://dimg04.c-ctrip.com/images/0230b12000dksynf916A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000dksyuibC2E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000dksyhj37BC0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000dksyqdu86F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000dksyqjfAD05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000dksyxm7A624_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000dksy859A0E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000dksypuvA77C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000dksyu6968FD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-03', '红棉双床套房', '套房', '家庭亲子', 388, 0, 10, 9, '["公共设施"]'::jsonb, '公共设施', NULL, NULL),
('68027c82e3c98b0941765a66', '酒店富丽堂皇还有博物馆 卫生且干净', '["https://dimg04.c-ctrip.com/images/0230n12000f3cfh4t2407_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000f3clfaa3C83_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000f3c9vvq6901_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 17, 0, 4, 4, '["整体满意度","卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL),
('68027c82e3c98b0941765a67', '房间布置很温馨，有种回家的感觉!床特别舒服，躺在上面特别放松!床垫非常柔软!下午茶小点心味道很甜蜜。棒!各种卫生用品也很干净!后花园也很漂亮!早餐特别丰盛!确实是米其林的大厨烹饪的。有机会还会光顾!', '["https://dimg04.c-ctrip.com/images/0235o12000d3nno832A2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000d3mueq2DD24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000d3npnikC121_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000d3nrjsj47D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000d3nh5bl5CDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000d3nw9apFE31_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-01', '城央绿意双床房', '双床房', '家庭亲子', 99, 0, 1, 8, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027c82e3c98b0941765a68', '全家人都喜欢老牌五星，这次带老人和孩子在花园酒店住了五天，非常舒心。

三个大人一个孩子，订了两间房间。由于我是金卡会员，升级到了64平粤韵房，老人的房间也一起升级到了粤韵房。

粤韵房设施良好保养得宜，补给充足干净卫生。

员工礼貌得体，处处体现五星大酒店风范。

还有真的好漂亮啊！！！大堂阔气，瀑布霸气，不敢想象38年前就有这么好的酒店了。

来之前有人跟我说花园酒店很旧了很老了不要住，我想说完全不旧，保养相当好，前台小姐姐也说旧的房间也一直在做升级改造，以后估计都会以全新面貌示人。

位置相当好！旁边利苑、点都德、八合里，吃东西太方便啦，叫外卖也好方便，吃的可太多了！！！

下面说下不太满意的。

办理入住好慢啊……刚开始一个外籍员工接待我，怎么说都不给我升级到粤韵，说只能升级到同面积新装修的房间，最后中国员工过来跟他说是可以的，外籍员工一脸懵说自己不知道。??

行政餐厅一般般哈，吃的东西好少，而且还搞过几次乌龙，一会儿说没查到行政待遇，一会儿又说有了，感觉外籍员工还是不太行。孩子起得晚，想说不在行政餐厅吃，让大人一起打包回去吃也不让，又不是吃完了再打包，不理解为什么不可以。

泳池只有露天的??。

瑕不掩瑜，总体入住还是很满意的，本来只订了3天，由于很满意又续住了两天，以后肯定也还会去住??。

对了，他们泳池后面有个儿童乐园，但是没啥人知道，没有孩子玩儿??。', '["https://dimg04.c-ctrip.com/images/0235u12000cvn7nqzDC7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000cvnhrquE0D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000cvnhc4jB2CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000cvnjolt6ABF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000cvno5cpC76C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000cvnods79B22_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000cvndglz1FA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000cvnn52qB395_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000cvnoosz5096_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-07', '花园大床房', '大床房', '家庭亲子', 596, 0, 17, 9, '["整体满意度","房间设施","周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套'),
('68027c82e3c98b0941765a69', '花园酒店的工作人员服务很好，套房重新装修环境不错', '["https://dimg04.c-ctrip.com/images/0233w12000e6ciepuADD3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000e6ccokpDE90_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000e6cxnxy1540_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-26', '花园大床房', '大床房', '商务出差', 24, 0, 2, 6, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027c82e3c98b0941765a6a', '环境真的是一流，中餐厅桃园馆菜品质量很高，服务员热情友好。客房卫生做的很好，房间设施齐全布局合理，不足之处是没有浴缸，酒店后花园非常值得看看走走，酒店的四楼博物馆也很值得一看，酒店服务人员态度都不错，就是前台接待人员态度一般，工作能力有些欠缺，退房后忘记退押金，居然开票资料还丢失了，经电话联系酒店后及时退还了押金并开具了发票，这点有些不可思议，入住多家广州五星级酒店还是第一次碰到。', '["https://dimg04.c-ctrip.com/images/0230i12000cn0xiy814C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000cn1169j2281_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000cn0vq0xEC3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000cn0zrbs4E9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000cn11akm976A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000cn0yaz59AB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000cn11cp63C9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000cn11cul3A7A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000cn11a5sAE59_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-11-26', '粤韵双床套房', '套房', '情侣出游', 192, 1, 49, 9, '["前台服务","房间设施","卫生状况"]'::jsonb, '前台服务', '房间设施', '卫生状况'),
('68027c82e3c98b0941765a6b', '第二次入住花园饭店，大堂的“金陵十二钗”大气磅礴，很有年代感的酒店，但是保养的很好，房间舒适，床垫有点偏软，酒店的网红花园和瀑布很好逛，拍照也出片。我们还打卡了酒店的博物馆，下次来广州，应该还会选择花园！', '["https://dimg04.c-ctrip.com/images/0230t12000d6mqj4k6A1D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000d6mq6i86CA9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-12', '粤韵双床套房', '套房', '家庭亲子', 102, 0, 34, 8, '["整体满意度","公共设施","房间设施"]'::jsonb, '整体满意度', '公共设施', '房间设施'),
('68027c8de3c98b0941765a6c', '算是地标性的酒店了，就在淘金路地铁站旁边，附近知名的饭店酒楼很多，打车也很方便。但设施太老了，基础房型对老人洗浴不太友好，容易滑倒。建议带老人家的，升级房型。', '["https://dimg04.c-ctrip.com/images/0230s12000dc8uugv605B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000dc8r59eEF0E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000dc8fkxj7BE4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-03-04', '花园双床房', '双床房', '家庭亲子', 79, 0, 65, 8, '["交通便利性","周边配套","房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施'),
('68027c8de3c98b0941765a6d', '房间太老旧，给的房间门缝漏光，不隔音。一张床的床垫还有一个坑。但是都说老牌花园酒店是粤式生活的代表还是住来这里。环境没得说，尤其是花园太美。早餐非常棒。希望抓紧改造老旧破的房间，别再让我们下次运气不好碰上这么差的房间。', '["https://dimg04.c-ctrip.com/images/0235912000d8pwea7260E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000d8pws632CA9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-02-19', '花园双床房', '双床房', '朋友出游', 109, 0, 6, 8, '["房间设施","安静程度","餐饮设施"]'::jsonb, '房间设施', '安静程度', '餐饮设施'),
('68027c8de3c98b0941765a6e', '入住愉快，但是一定要搭配套餐入住对连住不是很友好。', '["https://dimg04.c-ctrip.com/images/0230y12000e4v1q1mF350_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000e4tued96B74_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000e4u7lh361E7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-05-24', '羊羊得意主题大床房', '主题房', '家庭亲子', 25, 0, 75, 4, '["性价比","整体满意度"]'::jsonb, '性价比', '整体满意度', NULL),
('68027c8de3c98b0941765a6f', '酒店位置很好，晚上吃了晚饭可以步行去花城广场，走过可以看到小蛮腰，酒店的22楼办入住，也可以看到小蛮腰，周边吃饭很方便，离陶陶居很近，离春，夏，秋，冬商场很近，早餐品钟很丰富，广州的特色早餐都有，还有豆浆，豆浆是现磨的，味道很浓，上面还有一层豆皮，下次来广州还会入住这家酒店', '["https://dimg04.c-ctrip.com/images/0231u12000cywttyq21A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000cywti12A3F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000cywtquaD608_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-01-18', '花园双床房', '双床房', '家庭亲子', 137, 0, 8, 8, '["周边配套","餐饮设施","整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度'),
('68027c8de3c98b0941765a70', '房间舒适，干净卫生，住的很舒心。过年酒店很有节日气氛，服务态度很好，帮忙拍照，拿行李，贴心用心暖心。
交通便利，出行方便。
酒店很有历史底蕴，博物馆，木质旋转楼梯，红楼梦壁画，后花园都值得一逛。', '["https://dimg04.c-ctrip.com/images/0233u12000d7oo7zlB226_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000d7oknnp43DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000d7oo7l0A9AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000d7oro2l9727_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000d7ojkot0449_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000d7ostmkCB72_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '花园大床房', '大床房', '朋友出游', 97, 0, 5, 8, '["整体满意度","前台服务","交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性'),
('68027c8de3c98b0941765a71', '逢人就推荐，花园酒店的大堂太美了，一个有40年底蕴的酒店的装修媲美新酒店。感谢前台小姐姐给我升级了粤韵，秒变套房非常惊喜，哈哈。酒店内有博物馆和小花园，还有n多个餐厅，在等房间时，酒店内吃饭，再去参观博物馆溜达小花园，完美。', '["https://dimg04.c-ctrip.com/images/0234o12000czrcqvt8AA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000czr0jcxE977_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000czrh9ni8A5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000czr8u7vD8EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000czrcae0F485_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000czrm42u2640_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-21', '花园大床房', '大床房', '独自旅行', 112, 0, 18, 9, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027c8de3c98b0941765a72', '酒店很有历史，但设施并不陈旧，尤其公共区域维护非常好。房间内设施不奢华但是好用

酒店服务人员素质非常高，热情真诚得体。酒店内餐厅也是素质相当高

非常满意的入住体验', '["https://dimg04.c-ctrip.com/images/0233012000d7ahm8iB0FF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-14', '花园行政大床套房', '套房', '家庭亲子', 83, 0, 7, 7, '["整体满意度","公共设施","房间设施"]'::jsonb, '整体满意度', '公共设施', '房间设施'),
('68027c8de3c98b0941765a73', '整体感觉都非常好，特别感谢前台漂亮的小姐姐给我父母升了房间，让他们感受了不一样的酒店感受。房间很大很舒服，酒店每个人的服务都是100分，早餐也很丰盛，是个完美的度假体验。', '["https://dimg04.c-ctrip.com/images/0234l12000d5rq4z54A63_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000d5rpz8m71C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000d5rp89sAE47_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-08', '花园双床房', '双床房', '家庭亲子', 85, 0, 14, 8, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027c8de3c98b0941765a74', '每次小假期都会选择本地出游，首选都是花园酒店，特别喜欢这里的游泳池，大堂的布置很有特色每次都眼前一亮，最重要的是五星级的服务和卫生真的让人放心。特别感谢迎送岗的小爱，中秋节当天很开心收到酒店月饼～???', '["https://dimg04.c-ctrip.com/images/0233a12000fobgkwrD74D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000fob3cq52989_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000foblep23348_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-21', '花园大床房', '大床房', '情侣出游', 101, 0, 2, 8, '["公共设施","整体满意度","卫生状况"]'::jsonb, '公共设施', '整体满意度', '卫生状况'),
('68027c8de3c98b0941765a75', '花园酒店属于店如其名，花园真的很大很有逛小公园的感觉，邓爷爷题的字～很好逛，酒店内的饭店也是米其林推荐，的确味道都很不错，就是真的很贵～500一顿完全不够～毕竟广州物廉价美的食物真的很多～不过味道的确很不错，都很好吃～就是旅游还要回来吃饭其实不大方便哈哈哈??，适合local或者行程很朵悠悠的朋友～性价比还是很不错滴
设施：好像给我升级了新装修的套房定的我看有地毯，升级的这个说是新的，是没地毯的，但说实话房间有点旧，我这间墙面和沙发，还有点脏，就大堂和花园是加分项，房间就要扣分了，不过能看到半个小蛮腰还挺大的，就扣一分意思意思吧
卫生：房间卫生一般，可能因为墙面和椅子真的显得很脏
环境：很不错，本身地理位置很好门口就是地铁站，去地标距离都不远，地铁又实惠，又方便，打车看路况地段感觉都满堵的，来回地铁乘三天20大概??
服务：外国客人挺多的，所以服务员也是各个肤色，都很不错～客气??

最后一天看到了谭咏麟哈哈哈哈～
对了每天还有小点心', '["https://dimg04.c-ctrip.com/images/0232812000d1eynhwB5E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000d1f56ibB5BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000d1f23b92B36_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-25', '红棉大床套房', '套房', '家庭亲子', 423, 0, 31, 8, '["周边配套","性价比","卫生状况"]'::jsonb, '周边配套', '性价比', '卫生状况'),
('68027c98e3c98b0941765a76', '入住体验大大超过预期，真不愧为是中国酒店业的标杆，很有老钱风，设施非常齐全和豪华。居然还有博物馆，几个餐厅都是顶级的。服务员很热情专业训练有素，特别感谢服务员小玲。', '["https://dimg04.c-ctrip.com/images/0236g12000fbwh5858EF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000fbwc2wf3B60_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-31', '花园大床房', '大床房', '商务出差', 82, 0, 41, 9, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027c98e3c98b0941765a77', '对酒店的服务人员的态度非常满意，见面问好有礼貌，帮助按电梯，房间卫生干净整洁，有胶囊咖啡机，有欢迎水果和鲜花，酒店还有后花园，小桥流水锦鲤满池，地理位置优越，对面就是广州友谊商店，地铁淘金站就在酒店正门，这两天广州气温骤降酒店马上给热空调，我们是下午的飞机经理还帮我们延迟退房到14:00，很温馨的酒店，下次来广州再入住这家！', '["https://dimg04.c-ctrip.com/images/0230812000d0zhdlwEF74_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000d0zgs51A32E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000d0zgvtl23EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000d0zhpueD5DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-24', '城央绿意双床房', '双床房', '情侣出游', 163, 0, 27, 9, '["前台服务","卫生状况","交通便利性"]'::jsonb, '前台服务', '卫生状况', '交通便利性'),
('68027c98e3c98b0941765a78', '服务很好，房间很舒服，一千多的房间里面的胶囊咖啡机有三种口味，可供选择，大堂也很舒服明亮，总体来说感觉很好，一共住了四个晚上，出门非常方便，好吃的有名气的餐厅都在附近一公里范围。', '["https://dimg04.c-ctrip.com/images/0230k12000d23wl4m2680_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000d23qbpb56C6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-27', '花园大床房', '大床房', '独自旅行', 89, 0, 22, 8, '["整体满意度","房间设施","周边配套"]'::jsonb, '整体满意度', '房间设施', '周边配套'),
('68027c98e3c98b0941765a79', '走进大堂就是一个繁花迷人眼，让人目不暇接。卫生据肉眼可见还是很干净的，客房服务员，门童等都很热情，前台Gillian服务非常热情，亲切，周到，有求必应！', '["https://dimg04.c-ctrip.com/images/0230v12000d5gapxiACED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000d5gbu84A715_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000d5gcb4pFC31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000d5gax6a83F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000d5gc95r882E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000d5gbhbu6469_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000d5gcmn9B24C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000d5gcihs77BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000d5gbev736C3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-07', '花园大床房', '大床房', '独自旅行', 76, 0, 10, 7, '["前台服务","客房服务","卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况'),
('68027c98e3c98b0941765a7a', '不愧是白金五星，酒店地理位置优越，闹中取静，自带岭南风格的花园，还贴心地送了小点心', '["https://dimg04.c-ctrip.com/images/0231z224x8uhjlnud9651_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o224x8uhkjgps8E8D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i224x8uhk42ewF4F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q224x8uhk98g888F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r224x8uhka9nl1130_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-12', '城央绿意大床房', '大床房', '独自旅行', 41, 0, 22, 8, '["整体满意度","周边配套","安静程度"]'::jsonb, '整体满意度', '周边配套', '安静程度'),
('68027c98e3c98b0941765a7b', '大堂就很有春节气氛！房间应该经历过翻新，设施和装潢布局都很不错。被子估计是绒，轻薄又保暖。洗漱用具的盒子设计也充满巧思，可以构成一幅完整的广州市花木棉图案。', '["https://dimg04.c-ctrip.com/images/0231t12000d62b7p18A20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000d628op81F3D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000d62c4jc3420_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-09', '花园大床房', '大床房', '独自旅行', 78, 0, 46, 8, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027c98e3c98b0941765a7c', '酒店非常不错，是全国三个白金五星级酒店之一，入住时正好遇到中越一个商会搞活动，虽晚了一些但酒店给升级了套房而且还给了下午茶。酒店服务非常专业，感谢Rebecca小钟的热心服务和讲解，酒店近6号地铁交通便利，而且酒店有大巴直接到澳门几个固定地点，不过每天只有8:35这一班。酒店的瀑布餐厅很有特色，老人孩子非常满意，非常不错的一次体验。下次来广东还会再次入住。', '["https://dimg04.c-ctrip.com/images/0234i12000humufzq465E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000humobj20E65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000humgr1355E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-17', '花园双床房', '双床房', '家庭亲子', 179, 0, 14, 9, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027c98e3c98b0941765a7d', '服务很好，身体不舒服李文（名字写的不知道对不对）小姐姐帮忙处理加急拿房，房间吐了清洁的工作人员特别及时有耐心的清理。定的房型12岁以下免费加了床，非常适合我们这种娃年龄小块头大的。周边有陶陶居，点都德，广州酒家，常来小聚，步行可到，非常方便。', '["https://dimg04.c-ctrip.com/images/0233o12000ic88y3n12FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000ic88fkv7455_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000ic7qeurA1AE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-06', '红棉大床套房', '套房', '家庭亲子', 121, 0, 1, 8, '["前台服务","客房服务","周边配套"]'::jsonb, '前台服务', '客房服务', '周边配套'),
('68027c98e3c98b0941765a7e', '和同事相约游广东，恰逢圣诞在广州花园酒店连住2晚实在是选对了。
这个酒店太让人惊艳了，他们是全国首批三家白金五星级饭店之一，而且是华南地区唯一获选的中国自主品牌酒店。
贝聿铭为花园酒店勾画了建设蓝图，***为花园酒店奠基基石，邓小平为花园酒店亲笔题写了店名！
西点做得非常正宗美味，酒店米其林提名的餐厅不止一个，瀑布餐厅很有特色，服务非常好，非常满意，必须五星好评??', '["https://dimg04.c-ctrip.com/images/0230v12000d0a91nt05F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000d0acyi6CB42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000d0aodxk3210_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000d0ao6vsE3E8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000d0aodjg03F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000d0aodxq9FF4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000d0aodjk6D62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000d0ao6w23884_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000d0ap7yq145B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-22', '花园双床房', '双床房', '朋友出游', 184, 0, 35, 9, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68027c98e3c98b0941765a7f', '就在地铁淘金站出口，附近也很热闹，服务非常好，工作人员到处都是，房间装修也不错，除了卫生间没隔断有点不方便。新年有舞狮，有小摊，晚上还有驻场表演。', '["https://dimg04.c-ctrip.com/images/0232l12000d89zioq5C04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000d8a0q2e4144_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-17', '红棉大床套房', '套房', '家庭亲子', 73, 0, 4, 8, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68027caae3c98b0941765a80', '非常满意的一次住宿体验，颇具性价比。酒店很漂亮，交通方便，门口就是公交站和地铁站，服务人员态度很好，见面总是微笑打招呼，房间卫生还不错，没有异味。就是附近夜里有施工，稍微有点吵。花园很漂亮，常有打卡拍照的，二楼的早茶味道很不错。酒店旁边点都德，广州酒家离得很近。', '["https://dimg04.c-ctrip.com/images/0230x12000cw9q2dxC412_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cwa3qxfE9F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-09', '花园双床房', '双床房', '家庭亲子', 131, 0, 10, 8, '["交通便利性","性价比","整体满意度"]'::jsonb, '交通便利性', '性价比', '整体满意度'),
('68027caae3c98b0941765a81', '地理位置：酒店位于淘金地铁站出口处，前面还有数条公交线路，出行极其便利。
环境：酒店大堂金碧辉煌，前台的红楼梦壁画真是点睛之笔。
服务：从入口处的服务人员，到前台办理入住的接待人员，还有客房、餐厅的工作人员全程热情接待，笑脸相迎，让人如沐春风，可见酒店的管理水准到位，不愧为白金酒店的称谓??
餐饮：酒店的早餐品种繁多，菜品新鲜可口，服务人员热情友好，值得称赞??', '["https://dimg04.c-ctrip.com/images/0230g12000d1g97mmEF38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000d1g8ift3712_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000d1gif7lD1F2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-25', '花园双床房', '双床房', '朋友出游', 182, 0, 94, 9, '["交通便利性","前台服务","餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施'),
('68027caae3c98b0941765a82', '第二次住的花园酒店
传统地道的酒店年味是特别足，处处充满着粵广文化，另有一番滋味，早餐后逛逛花园，鸟语花香.

细致的服务也凸显出酒店管理的用心。', '["https://dimg04.c-ctrip.com/images/0233c12000d80le8i1204_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000d813rbg9CC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000d812vuf8D1A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-16', '红棉大床套房', '套房', '家庭亲子', 73, 0, 5, 7, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027caae3c98b0941765a83', '网约车司机是个健谈的广州人，听了他对酒店的推荐，临时决定在广州多停留一晚，结果出乎意料地满意。酒店如其名，真得像个花园一样，会推荐给朋友们。升级的粤韵套房宽敞，设施很新。参观了位于4层的酒店博物馆，才知道酒店始建于1984年，还是邓小平先生题字。酒店内及周边餐厅很多，丰俭由人。交通便捷，离地铁就2-3分钟步行距离。唯一的建议是夜间关闭瀑布，减少噪声。', '["https://dimg04.c-ctrip.com/images/0236s12000cw6u2rmDCCC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000cw6mqza879F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000cw6ibq66A9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000cw6s4olDDC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000cw6rjefB8E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000cw6s069D9E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000cw6vn9b8480_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000cw6vmom7B92_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-09', '花园双床房', '双床房', '家庭亲子', 176, 0, 41, 9, '["整体满意度","交通便利性","安静程度"]'::jsonb, '整体满意度', '交通便利性', '安静程度'),
('68027caae3c98b0941765a84', '非常好的酒店，下次还会再入住！酒店的餐厅要去试试！', '["https://dimg04.c-ctrip.com/images/0230t12000e22mqyr41DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000e22n370E9E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000e22ll11EC72_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000e22aebc669D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000e2263684027_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-18', '粤韵大床套房', '套房', '商务出差', 25, 0, 43, 4, '["整体满意度","餐饮设施"]'::jsonb, '整体满意度', '餐饮设施', NULL),
('68027caae3c98b0941765a85', '非常喜欢叫啊看看o', '["https://dimg04.c-ctrip.com/images/0232x12000eh8jpczA39F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-14', '花园大床房', '大床房', '商务出差', 9, 0, 5, 1, '[]'::jsonb, NULL, NULL, NULL),
('68027cabe3c98b0941765a86', '设施：足够齐全，就是不知道哪些收费哪些免费

卫生：卫生特别过关

环境：环境确实没得说，各个餐厅也是非常好
服务：服务非常到位，就是餐厅有额外服务费', '["https://dimg04.c-ctrip.com/images/0235v12000d6ivxyw2E8C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000d6j17uo5CA5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000d6ize2m7F5D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '粤韵双床套房', '套房', '家庭亲子', 75, 0, 10, 6, '["餐饮设施","卫生状况","整体满意度"]'::jsonb, '餐饮设施', '卫生状况', '整体满意度'),
('68027cabe3c98b0941765a87', '房间非常干净舒适', '["https://dimg04.c-ctrip.com/images/02352324x8vzgmbx462AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-19', '花园大床房', '大床房', '独自旅行', 8, 0, 1, 4, '["卫生状况","整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL),
('68027cabe3c98b0941765a88', '酒店年味十足，喜庆气氛满满，餐饮美味服务好。全家在这里渡过愉快的龙年春节，开启顺利吉祥的新年，非常满意??', '["https://dimg04.c-ctrip.com/images/0235b12000d7vszigB5BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000d7vsuoy32A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000d7vt0nh2AFF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000d7vszikFD33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000d7vtaht62B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000d7vszbz2E5B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000d7vtdmuAD70_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000d7vt3ue0C6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000d7vswuf6F5E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-16', '粤韵大床套房', '套房', '家庭亲子', 53, 0, 6, 5, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027cabe3c98b0941765a89', '服务很好??地铁方便??环境特别美??', '["https://dimg04.c-ctrip.com/images/0234212000ewypi9f400F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000ewyq7s42478_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000ewymllb9462_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000ewymlld2939_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000ewyjmp00608_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000ewyendkC21D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-27', '花园双床房', '双床房', '朋友出游', 19, 0, 34, 4, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027cb5e3c98b0941765a8a', '多次来广州出差，都是选择入住广州花园酒店，一进门大堂金碧辉煌，环境卫生管理非常好，房间设施设备也非常齐全，特别谢谢前厅部副经理 吴灵伶，服务很热情，虽然是第一次见面，但是微笑热情洋溢，给人一种如沐春风的感觉，为她点赞??', '["https://dimg04.c-ctrip.com/images/0233p12000iwy8eqjDEA1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000iwydyuv7CE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000iwwfr5qB533_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000iwy63htC591_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-06', '花园大床房', '大床房', '商务出差', 110, 0, 10, 8, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027cb5e3c98b0941765a8b', '酒店位于市中心，门口就是地铁淘金站，对面是白云宾馆。交通非常便利。
酒店有六间餐厅，吃东西很方便。酒店花园不算特别大，有两个大瀑布，庭院，假山，小桥，流水，非常惬意。酒店的电梯运行很快，很稳，不需要等很久。j订的红棉套房还包括五百块酒店餐厅消费券，可直接使用，很方便。房间装潢虽然有年代感，但使用起来没有任何问题。
床偏软了点，平时睡惯了硬床，有点不习惯了。
早餐的瀑布餐厅比较小，要排队，建议早点去
前台办入住时等了不少时间，效率稍微差点。
另酒店的博物馆值得去刷一下，有免费讲解。', '["https://dimg04.c-ctrip.com/images/023222215h3zsm4hs69F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m2224x7cyp3dc56A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023662234daq4s9yo9DFF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k2234daq4shog76C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f2234daq4spe84600_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w2215h3zsnesg3E81_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p2215h3zsnesh5ED4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f2234daq4t4tsBC48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l2215h3zso1xs7FB0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-22', '红棉双床套房', '套房', '朋友出游', 242, 2, 12, 9, '["交通便利性","周边配套","退房/入住效率"]'::jsonb, '交通便利性', '周边配套', '退房/入住效率'),
('68027cb5e3c98b0941765a8c', '非常满意，因为飞机延误了房务小何还帮我们申请延迟了退房，游泳池小孩也特别开心，下次来广州还住这里，棒棒哒！', '["https://dimg04.c-ctrip.com/images/0235x12000eebverv47EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000eebxno12AA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000eebp0fa3A58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000eec2a0b5C0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000eebvnsb608B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-09', '红棉双床套房', '套房', '家庭亲子', 53, 0, 4, 7, '["前台服务","公共设施","整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度'),
('68027cb5e3c98b0941765a8d', '除了办理入住的时候特别慢，其他服务都很不错
果然是老牌五星级，各种服务还是很到位的！送的生日小点心也好看又好吃！
而且花园酒店里面拍照也好出片，配上我的马面裙好好看！
瀑布餐厅：照片真的很好看，随便拍拍都好看，但早餐品类太少了，是我吃过五星级餐厅里面少的可怜的了，厨师连蛋卷都煎不好，差评！
荔湾亭：个人感觉名不符实了，价格的确高，菜量实在小，重点是问题只能说是平平无奇，就很正常的味道，没有惊艳之处。', '["https://dimg04.c-ctrip.com/images/0232u12000coapd6sF694_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000coatg6g5BBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000coas4o6FC55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000coas3ku1065_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000coatkc12721_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000coasrfnA2D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000coavang0BC6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000coal2yh35AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000coapd6v5AC4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-03', '红棉大床套房', '套房', '情侣出游', 201, 2, 1, 9, '["前台服务","退房/入住效率","餐饮设施"]'::jsonb, '前台服务', '退房/入住效率', '餐饮设施')
 ON CONFLICT (_id) DO NOTHING;
